const crypto = require('crypto');
const token = crypto.randomBytes(32).toString('hex');
return [{ json: { acceptance_token: token } }];

const ctx = $input.first().json;
const aUrl = `https://{{N8N_BASE_URL}}/webhook/quote-accept?token=${ctx.acceptance_token}`;
const dUrl = `https://{{N8N_BASE_URL}}/webhook/quote-decline?token=${ctx.acceptance_token}`;
const total = parseFloat(ctx.final_total || 0).toFixed(2);
const html = `<!DOCTYPE html><html><body style="font-family:Arial;max-width:620px;margin:0 auto"><div style="background:#4A148C;padding:22px 8px;border-radius:8px 8px 0 0"><h1 style="color:#fff;margin:0">Apex Windows TX</h1><p style="color:#CE93D8;margin:5px 0 0">Your Quote is Ready</p></div><div style="padding:24px;background:#fafafa"><p>Hi ${ctx.lead_name},</p><p>Here is your personalised quote for your window service:</p><table style="width:100%;border-collapse:collapse;margin:14px 0"><tr style="background:#4A148C"><th style="color:#fff;padding:9px;text-align:left">Service</th><th style="color:#fff;padding:9px;text-align:right">Price</th></tr><tr><td style="padding:9px">Window Service</td><td style="padding:9px;text-align:right">$${total}</td></tr></table><div style="text-align:center;margin:28px 0"><a href="${aUrl}" style="background:#2E7D32;color:#fff;padding:15px 30px;border-radius:6px;text-decoration:none;font-size:17px;font-weight:bold">Accept This Quote</a></div><p style="text-align:center;font-size:12px;color:#aaa">Not interested? <a href="${dUrl}">Decline here</a></p><p style="font-size:12px;text-align:center">Questions? Call 214-555-0100</p><p style="font-size:11px;color:#ccc;text-align:center;margin-top:16px">[TEST EMAIL]</p></div></body></html>`;
return [{ json: { ...ctx, quote_html: html } }];

const lead_id = $('Webhook - Job Completed').first().json.body.lead_id;
const marked_by = $('Webhook - Job Completed').first().json.body.marked_by || 'Alvin';
const yr = new Date().getFullYear();
const num = 'APX-' + yr + '-' + String(Math.floor(Math.random()*9000)+1000);
const due = new Date(Date.now()+14*86400000).toISOString().split('T')[0];
return [{ json: { invoice_number: num, invoice_date: new Date().toISOString().split('T')[0], due_date: due, lead_id, marked_by } }];

const d = $('Payment Check Data').first().json;
return [{ json: {
  status: 'partial',
  invoice_id: d.invoice_id,
  lead_id: d.lead_id,
  invoice_number: d.invoice_number,
  amount_paid: d.amount_paid,
  balance: d.amount_due - d.amount_paid
} }];

const d = $input.first().json;
const b = d.body || {};
return [{ json: {
  invoice_number: d.invoice_number || b.invoice_number,
  amount_paid:    Number(d.amount_paid   || b.amount_paid   || 0),
  payment_method: d.payment_method || b.payment_method || 'manual',
  transaction_id: d.transaction_id || b.transaction_id || null
} }];

const body = $input.first().json.body || {};
if (body.type !== 'checkout.session.completed') return [];
const s = body.data && body.data.object;
if (!s || s.payment_status !== 'paid') return [];
return [{ json: {
  invoice_number: (s.metadata || {}).invoice_number,
  amount_paid:    (s.amount_total || 0) / 100,
  payment_method: 'stripe',
  transaction_id: s.payment_intent || s.id
} }];

const body = $('Webhook - Manager Approved').first().json.body || $('Webhook - Manager Approved').first().json;
const adjusted_price = body.adjusted_price;

// Pass through if no price adjustment submitted
if (adjusted_price === undefined || adjusted_price === null || adjusted_price === '') {
  return $input.all();
}

const price = parseFloat(adjusted_price);
if (isNaN(price)) {
  throw new Error(`Invalid adjusted_price: "${adjusted_price}" is not a valid number.`);
}
if (price < 0) {
  throw new Error(`Invalid adjusted_price: cannot be negative. Received: $${price}.`);
}
if (price > 25000) {
  throw new Error(`Invalid adjusted_price: $${price.toFixed(2)} exceeds the $25,000 safety cap. Please verify the amount and contact support if correct.`);
}

return $input.all();
